import React, { useState } from "react";

const TemplateSelector = ({
  showModal,
  setShowModal,
  templates,
  onTemplateSelect,
  selectedQueueEntry,
}) => {
  const [selectedTemplate, setSelectedTemplate] = useState(null);
  const [editedSubject, setEditedSubject] = useState("");
  const [editedBody, setEditedBody] = useState("");
  const [editedToEmail, setEditedToEmail] = useState("");
  const [isSending, setIsSending] = useState(false);

  if (!showModal) return null;

  const handleSelectTemplate = (template) => {
    setSelectedTemplate(template);
    // Replace placeholders for display
    let subject = template.subject;
    let body = template.body;

    const placeholders = {
      "{{study_title}}": selectedQueueEntry?.study_title || "N/A",
      "{{nct_id}}": selectedQueueEntry?.nct_id || "N/A",
      "{{contact_name}}": selectedQueueEntry?.contact_name || "Participant",
      "{{contact_email}}": selectedQueueEntry?.contact_email || "N/A",
      "{{date}}": new Date().toLocaleDateString(),
      "{{time}}": new Date().toLocaleTimeString(),
      "{{phase}}": selectedQueueEntry?.phase || "N/A",
      "{{condition}}": selectedQueueEntry?.condition_name || "N/A",
      "{{location}}": selectedQueueEntry?.location || "N/A",
      "{{status}}": selectedQueueEntry?.status || "N/A",
    };

    Object.entries(placeholders).forEach(([key, value]) => {
      subject = subject.replace(new RegExp(key, "g"), value);
      body = body.replace(new RegExp(key, "g"), value);
    });

    setEditedSubject(subject);
    setEditedBody(body);
  };

  const handleSendEmail = async () => {
    if (!selectedTemplate || !selectedQueueEntry) {
      alert("Please select a template");
      return;
    }

    if (!editedToEmail || editedToEmail.trim() === "") {
      alert("Please enter a recipient email address");
      return;
    }

    setIsSending(true);

    try {
      let attachments = [];
      if (selectedTemplate.attachments) {
        if (typeof selectedTemplate.attachments === 'string') {
          try {
            attachments = JSON.parse(selectedTemplate.attachments);
          } catch (e) {
            attachments = [];
          }
        } else if (Array.isArray(selectedTemplate.attachments)) {
          attachments = selectedTemplate.attachments;
        }
      }

      await onTemplateSelect(
        {
          ...selectedTemplate,
          subject: editedSubject,
          body: editedBody,
        },
        {
          ...selectedQueueEntry,
          contact_email: editedToEmail,
        }
      );

      setShowModal(false);
      setSelectedTemplate(null);
      setEditedSubject("");
      setEditedBody("");
      setEditedToEmail("");
    } catch (error) {
      console.error("Error sending email:", error);
    } finally {
      setIsSending(false);
    }
  };

  return (
    <div className="fixed inset-0 bg-black/80 z-[100] flex items-center justify-center p-4">
      <div className="bg-[#0b0f2e] border border-white/10 rounded-lg w-full max-w-6xl max-h-[100vh] overflow-hidden flex flex-col">
        {/* Header */}
        <div className="border-b border-white/10 p-5 flex justify-between items-center bg-white/2">
          <h3 className="text-base font-semibold text-white">Send Email</h3>
          <button
            onClick={() => {
              setShowModal(false);
              setSelectedTemplate(null);
            }}
            className="text-white/70 hover:text-white text-2xl transition"
          >
            ✕
          </button>
        </div>

        {/* Content */}
        <div className="flex flex-1 overflow-hidden">
          {/* Templates List - Sidebar */}
          <div className="w-56 border-r border-white/10 overflow-y-auto p-4">
            <p className="text-xs font-semibold text-white/50 mb-3 uppercase">Templates</p>
            <div className="space-y-2">
              {templates.length === 0 ? (
                <p className="text-xs text-white/40 py-4">No templates</p>
              ) : (
                templates.map((template) => (
                  <button
                    key={template.id}
                    onClick={() => handleSelectTemplate(template)}
                    className={`w-full text-left p-3 rounded-md transition border text-xs ${
                      selectedTemplate?.id === template.id
                        ? "bg-indigo-600/30 border-indigo-500/50 text-white"
                        : "bg-white/5 border-white/10 text-white/80 hover:bg-white/10"
                    }`}
                  >
                    <p className="font-medium truncate">{template.name}</p>
                  </button>
                ))
              )}
            </div>
          </div>

          {/* Email Editor */}
          <div className="flex-1 overflow-y-auto p-6">
            {selectedTemplate ? (
              <div className="space-y-4 max-w-2xl">
                {/* From/To */}
                <div className="grid grid-cols-2 gap-3">
                  <div>
                    <label className="text-xs font-medium text-white/60 mb-1.5 block">From</label>
                    <input
                      type="text"
                      value="info@aicruitment.com"
                      readOnly
                      className="w-full bg-white/5 border border-white/10 text-white rounded px-3 py-2 text-xs"
                    />
                  </div>
                  <div>
                    <label className="text-xs font-medium text-white/60 mb-1.5 block">To</label>
                    <input
                      type="email"
                      value={editedToEmail || selectedQueueEntry?.contact_email || ""}
                      onChange={(e) => setEditedToEmail(e.target.value)}
                      className="w-full bg-white/5 border border-white/10 text-white rounded px-3 py-2 text-xs focus:outline-none focus:border-indigo-500 focus:ring-1 focus:ring-indigo-500/30"
                      placeholder="email@example.com"
                    />
                  </div>
                </div>

                {/* Subject */}
                <div>
                  <label className="text-xs font-medium text-white/60 mb-1.5 block">Subject</label>
                  <input
                    type="text"
                    value={editedSubject}
                    onChange={(e) => setEditedSubject(e.target.value)}
                    className="w-full bg-white/5 border border-white/10 text-white rounded px-3 py-2 text-sm focus:outline-none focus:border-indigo-500 focus:ring-1 focus:ring-indigo-500/30"
                    placeholder="Email subject"
                  />
                </div>

                {/* Body */}
                <div>
                  <label className="text-xs font-medium text-white/60 mb-1.5 block">Message</label>
                  <textarea
                    value={editedBody}
                    onChange={(e) => setEditedBody(e.target.value)}
                    rows="7"
                    className="w-full bg-white/5 border border-white/10 text-white rounded px-3 py-2 text-xs focus:outline-none focus:border-indigo-500 focus:ring-1 focus:ring-indigo-500/30 resize-none"
                    placeholder="Email message"
                  />
                </div>

                {/* Attachments - Compact */}
                {selectedTemplate.attachments && selectedTemplate.attachments.length > 0 && (
                  <div className="text-xs">
                    <p className="text-white/60 mb-2">
                      📎 {(Array.isArray(selectedTemplate.attachments) ? selectedTemplate.attachments : JSON.parse(selectedTemplate.attachments || "[]")).length} attachment(s)
                    </p>
                  </div>
                )}
              </div>
            ) : (
              <div className="flex items-center justify-center h-full text-center">
                <div>
                  <p className="text-4xl mb-2">←</p>
                  <p className="text-sm text-white/50">Select a template</p>
                </div>
              </div>
            )}
          </div>
        </div>

        {/* Footer */}
        <div className="border-t border-white/10 p-4 flex gap-2 justify-end bg-white/2">
          <button
            onClick={() => setShowModal(false)}
            className="px-4 py-2 border border-white/20 text-white text-xs rounded hover:bg-white/10 transition"
          >
            Cancel
          </button>
          <button
            onClick={handleSendEmail}
            disabled={!selectedTemplate || isSending}
            className="px-5 py-2 bg-indigo-600 text-white text-xs rounded hover:bg-indigo-700 transition disabled:opacity-50 disabled:cursor-not-allowed"
          >
            {isSending ? "Sending..." : "Send Email"}
          </button>
        </div>
      </div>
    </div>
  );
};

export default TemplateSelector;